    "startFrame": 23671,
    "durationSec": 5.461333333333333,
    "durationFrames": 164,
    "speaker": "ずんだもん",
    "text": "5Gの真価はスマホの速度じゃなく、産業インフラにあるかもしれないのだ。",
    "speakerColor": "#22c55e",
    "sceneId": 15,
    "sceneTitle": "未来への展望",
